.overlay {
  position: fixed; inset: 0;
  clip-path: circle(0px at calc(100% - 50px) 40px); /* ☰ 버튼 중심 좌표 */
  transition: clip-path 640ms cubic-bezier(0.76,0,0.24,1);
}
body.menu-open .overlay {
  clip-path: circle(142% at calc(100% - 50px) 40px); /* 뷰포트 대각선을 덮는 반경 */
}
.ov-link { opacity: 0; transform: translateY(18px); }
body.menu-open .ov-link { opacity: 1; transform: none; transition-delay: calc(260ms + var(--i) * 60ms); }

var btn = document.querySelector(".menu-btn");
var overlay = document.querySelector(".overlay");
function setOpen(open){
  document.body.classList.toggle("menu-open", open);
  document.body.style.overflow = open ? "hidden" : "";   /* 스크롤 잠금 */
  btn.setAttribute("aria-expanded", open);
  overlay.setAttribute("aria-hidden", !open);
  if (open) overlay.querySelector(".ov-link").focus();   /* 포커스 이동 */
  else btn.focus();
}
btn.addEventListener("click", function(){ setOpen(!document.body.classList.contains("menu-open")); });
document.addEventListener("keydown", function(e){ if (e.key === "Escape") setOpen(false); });

.ov-dim { position: absolute; inset: 0; background: rgba(0,0,0,0.55); opacity: 0; transition: opacity 420ms ease; }
body.menu-open .ov-dim { opacity: 1; }
.ov-panel {
  position: absolute; top: 0; right: 0; bottom: 0; width: min(420px, 88vw);
  transform: translateX(100%);
  transition: transform 480ms cubic-bezier(0.76,0,0.24,1);
}
body.menu-open .ov-panel { transform: translateX(0); }

