.ov-txt { display: inline-block; overflow: hidden; vertical-align: bottom; } /* 줄 마스크 */
.ov-txt .ch {
  display: inline-block;
  transform: translateY(112%) rotate(10deg); transform-origin: left bottom;
  transition: transform 240ms cubic-bezier(0.55,0,0.55,1); /* 닫힘: 짧고 균일 */
}
body.menu-open .ov-txt .ch {
  transform: translateY(0) rotate(0deg);
  transition: transform 480ms cubic-bezier(0.22,1,0.36,1);
  transition-delay: var(--d); /* JS가 링크×90ms + 글자×30ms로 주입 */
}

